import React, { useEffect, useMemo, useState } from 'react';
import { cultivationLogService, pondService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/manager/manager-common.css';
import '../../styles/manager/manager-cultivation-logs.css';
import { pushToast } from "../../utils/toastBridge";
const formatVietnameseDateTime = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const formatVietnameseDate = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const ManagerCultivationLogs = () => {
  const [ponds, setPonds] = useState([]);
  const [selectedPondId, setSelectedPondId] = useState('');
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const error = null;
  useEffect(() => {
    fetchPonds();
  }, []);
  useEffect(() => {
    if (!selectedPondId) {
      setLogs([]);
      return;
    }
    fetchLogs(selectedPondId);
  }, [selectedPondId]);
  const fetchPonds = async () => {
    try {
      setLoading(true);
      const response = await pondService.getAllPonds();
      const pondList = response?.data?.data || [];
      setPonds(pondList);
      if (pondList.length > 0) {
        setSelectedPondId(String(pondList[0].pond_id));
      }
    } catch (err) {
      pushToast({
        title: "ThÃ¤Ët bÃ¤Ài",
        message: err?.response?.data?.message || 'KhûôÇng tûÀô¤ôÈi ûãûô¯ûÀô£ôÈc danh sûôÀch ao nuûôÇi',
        type: "error"
      });
    } finally {
      setLoading(false);
    }
  };
  const fetchLogs = async pondId => {
    try {
      setLoadingLogs(true);
      const response = await cultivationLogService.getByPondId(pondId);
      setLogs(response?.data?.data || []);
    } catch (err) {
      pushToast({
        title: "ThÃ¤Ët bÃ¤Ài",
        message: err?.response?.data?.message || 'KhûôÇng tûÀô¤ôÈi ûãûô¯ûÀô£ôÈc nhûÀô¤ôÙt kûô§ xûÀô£ôÙ lûô§',
        type: "error"
      });
      setLogs([]);
    } finally {
      setLoadingLogs(false);
    }
  };
  const selectedPond = ponds.find(pond => String(pond.pond_id) === String(selectedPondId));
  const summary = useMemo(() => {
    const total = logs.length;
    return {
      total
    };
  }, [logs]);
  if (loading) {
    return <div className="dashboard-container manager-page">
        <div className="card">
          <div className="manager-cultivation-logs__loading">ûôang tûÀô¤ôÈi danh sûôÀch ao nuûôÇi...</div>
        </div>
      </div>;
  }
  return <div className="dashboard-container manager-page">
      <div className="manager-cultivation-logs__selector" style={{
      marginBottom: '1rem'
    }}>
        <select className="input" value={selectedPondId} onChange={e => setSelectedPondId(e.target.value)}>
          <option value="">-- ChûÀô£ôn ao nuûôÇi --</option>
          {ponds.map(pond => <option key={pond.pond_id} value={pond.pond_id}>
              {pond.pond_code} - {pond.pond_name}
            </option>)}
        </select>
      </div>

      {error && <div className="alert alert-danger">{error}</div>}

      <div className="manager-cultivation-logs__summary-grid" style={{
      display: 'flex',
      gap: '1rem',
      alignItems: 'stretch'
    }}>
        <div className="card" style={{
        flex: '0 0 200px'
      }}>
          <h3>TûÀô£ãÂng nhûÀô¤ôÙt kûô§</h3>
          <p className="manager-cultivation-logs__stat-value">{summary.total}</p>
        </div>
        <div className="card manager-cultivation-logs__info-card" style={{
        flex: '1'
      }}>
          <h3>ThûôÇng tin ao ûãang xem</h3>
          <p className="manager-cultivation-logs__info-title">{selectedPond ? `${selectedPond.pond_code} - ${selectedPond.pond_name}` : 'Chûô¯a chûÀô£ôn ao'}</p>
          <p className="manager-cultivation-logs__info-subtitle">{selectedPond ? `MûôÈ ao: ${selectedPond.pond_code}` : '-'}</p>
        </div>
      </div>

      <div className="card">
        <h3>Danh sûôÀch nhûÀô¤ôÙt kûô§ xûÀô£ôÙ lûô§</h3>
        <div className="table-responsive">
          <table className="table">
            <thead>
              <tr>
                <th>Ngûô y xûÀô£ôÙ lûô§</th>
                <th>Mûô¿a vûÀô£ôË</th>
                <th>NhûôÂn viûôˆn</th>
                <th>ûôûôÈ lûô m gûô˜</th>
                <th>Chi tiûÀô¤ô¢t</th>
                <th>Ghi lûô¤c</th>
              </tr>
            </thead>
            <tbody>
              {loadingLogs ? <tr>
                  <td colSpan="6">ûôang tûÀô¤ôÈi...</td>
                </tr> : logs.length === 0 ? <tr>
                  <td colSpan="6">Chûô¯a cûô° nhûÀô¤ôÙt kûô§ xûÀô£ôÙ lûô§ nûô o</td>
                </tr> : logs.map(log => <tr key={log.log_id}>
                    <td>{formatVietnameseDate(log.log_date)}</td>
                    <td>{log.season_name || `Mûô¿a vûÀô£ôË #${log.season_id}`}</td>
                    <td>{log.created_by_name || log.created_by_username || `#${log.created_by || '-'}`}</td>
                    <td>{log.action_type || '-'}</td>
                    <td className="manager-cultivation-logs__description">{log.description || '-'}</td>
                    <td>{formatVietnameseDateTime(log.created_at)}</td>
                  </tr>)}
            </tbody>
          </table>
        </div>
      </div>
    </div>;
};
export default ManagerCultivationLogs;
